#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 调香师与香水.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="调香师与香水"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 原料 / accord 定位
  9.2 IFRA / EU 合规版本核对
  9.3 创作约束语境定位（B2B brief ⇄ niche carte blanche）
  9.4 天然 vs 合成 + 可持续选型
  9.5 流派 / figure 视角定位
  9.6 祛魅校验：营销话术 vs 配方真相
  9.7 时效 / reformulation 风险 + stay-current

背后的心智模型:
  • codifiable 原料 ⇄ tacit 嗅觉记忆（第一性张力）: 这行可背诵的一半（原料、香料化学、accord 公式、挥发度、IFRA 限值）能进教科书；另一半——成为「the nose」的嗅觉记忆与品味——不可言传，只能靠每天盲嗅背料一克一克长出来。学校先让学徒
  • 暗示而非复刻：香水是「说真话的谎言」: 顶级调香不复刻自然，而是用（多为合成的）分子制造一个比真实更可信的**嗅觉幻觉**——Ellena 自称 illusionist，Ropion 的 Carnal Flower 是「扭曲/暗示一朵晚香玉
  • accord 是创作的「单词」，挥发度金字塔是它的语法: 创作不是「堆原料」而是「搭和弦」——accord 是 5–12 个原料失去各自身份、融成一个不可拆分的新气味单位（amber accord 由 labdanum+vanilla+benzoin 构成，

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "原料 / accord 定位"
  "IFRA / EU 合规版本核对"
  "创作约束语境定位（B2B brief ⇄ niche carte blanche）"
  "天然 vs 合成 + 可持续选型"
  "流派 / figure 视角定位"
  "祛魅校验：营销话术 vs 配方真相"
  "时效 / reformulation 风险 + stay-current"
)
declare -a DIM_QUESTIONS=(
  "用户问到的某个原料/香气是什么气味/强度/挥发度，归哪个家族，是天然还是合成、是否 captive，能否构成或属于某个 accord。"
  "某原料在目标品类（如 Cat 4 fine fragrance / Cat 12 candle）的现行限用浓度、是否被 Prohibition/Restriction、是否触发 EU 致敏原申报。"
  "用户/作品处在哪种创作世界——商业命题创作（core list 竞标、evaluator、consensus、复用 performing formula）还是 niche/indie 直营（从灵感起、carte blanche、自持配方）。"
  "该需求该用天然还是合成/发酵分子；可持续/濒危/气候约束下有无发酵法替代（檀香/ambrox/patchouli）；替代分子是否算「天然」。"
  "用户的问题落在哪个学派——方法论（Jean Carles）、极简美学（Roudnitska/Ellena）、overdose 技法（Ropion/Grojsman）、分类（Edwards）、批评（Turin/Burr）、天然派（Aftel/Tauer）。"
  "用户引用的说法是否是被资深从业者拒绝的营销话术（pheromone 吸引/therapeutic-grade/all-natural=safe/clean·non-toxic/24h lasting/dupe=identical/niche=always better）。"
  "经典香是否已因 IFRA/EU 被 reformulate（vintage vs 新版差异）；该领域最近 12 月变化（AI/发酵/法规落地）；跟踪需要哪些语言/源。"
)
declare -a DIM_SOURCES=(
  "原料查 TGSC（thegoodscentscompany.com，气味/CAS/IFRA/用量）；成品香型坐标查 Michael Edwards《Fragrances of the World》+ Fragrance Wheel（14 家族）；accord 概念查 canon（T04-S040）。**不要**用 Fragrantica note 金字塔当配方依据。"
  "IFRA Standards 官方（标明当前 Amendment 版本号，currently 51st）+ EUR-Lex Reg (EU) 2023/1545 原文；执行靠内建 IFRA 检测的配方软件。caveat：限值随版本变、天然不豁免。"
  "Track 03 工作流（B2B 模型 T03-S005 / IAO artisan 三条件 T03-S027）；判断信号：有无外部 brief、是否盲测、是否进 core list、是否自持品牌。"
  "Track 02 新兴层 #16（发酵法 Firsantol/Clearwood Prisma）+ ISO 9235「天然」口径 + 目标市场标签法规；天然安全性交叉 NCBI/ACHS（天然≠无致敏）。"
  "Track 01 figures + Track 04 谱系（§7 智识谱系）；用「这个问题谁会怎么答」反推视角。"
  "Track 06「厂商话术拒绝」7 条 + outsider-tell top 12，每条配机理反驳（PNAS pheromone 研究、CPTG 商标、reformulation 事实）。"
  "Track 03 #12 reformulation（oakmoss/Mitsouko/No.5）+ Track 06 法规时间轴 + Track 05 信息源（en 核心 + fr 深度，个人源 decay 与付费迁移）。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "1–2 句「该料/香气 = {家族}，{天然/合成/captive 状态}，挥发度落 {top/heart/base}，典型用于 {accord/场景}」+ 来源。"
  "「按 IFRA 第 N 修订版，{料} 在 {category} 限 {值/状态}；EU 2023/1545 下{是否需申报}」+ 版本号 + 来源（绝不用记忆里的旧限值）。"
  "「此为 {B2B / niche} 语境，决策受 {该约束} 支配；同一大师在另一端会 {如何不同}」——用约束解释行为，不用才华高低。"
  "「{天然/合成/发酵} 路线，理由 {成本/可持续/留香/合规}；注意 {ISO 9235 是否算天然 / 天然≠安全} 的争议」+ caveat（商业化里程碑多为厂商自报）。"
  "「此问题主要是 {学派} 的地盘，代表 {figure} 会主张 {立场}；对立派 {figure} 会反驳 {点}」——给出分歧而非和稀泥。"
  "「{该说法} 是营销话术，机理上 {一句反驳}；内行实际意思是 {正解}」——祛魅 + 给正确替代认知。"
  "「{该香/该料} {是否已重配 + 关键变化}；stay-current 看 {Esxence/IFEAT/Now Smell This/Bois de Jasmin 等 en+fr 源}」+ caveat（中文无对标一手、个人源易迁移）。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
